// JWKS client for fetching signing keys from the OIDC provider
const jwksClientInstance = jwksClient({
  jwksUri: OIDC_CONFIG.jwksUri,
  cache: true,
  cacheMaxEntries: 5,
  cacheMaxAge: 600000, // 10 minutes
  rateLimit: true,
  jwksRequestsPerMinute: 10,
});

// Function to retrieve the signing key from JWKS endpoint
function getSigningKey(header) {
  return new Promise((resolve, reject) => {
    jwksClientInstance.getSigningKey(header.kid, (err, key) => {
      if (err) {
        return reject(err);
      }
      const signingKey = key.getPublicKey();
      resolve(signingKey);
    });
  });
}

/**
 * Securely verify and decode the id_token JWT.
 * 
 * SECURITY NOTE: We use jwt.verify() with the provider's public key, NOT jwt.decode().
 * jwt.decode() does NOT verify the signature, which means:
 *   - An attacker could forge a token with arbitrary claims
 *   - There is no guarantee the token was issued by the trusted OIDC provider
 *   - Token expiration and audience checks would be bypassed
 * 
 * jwt.verify() ensures:
 *   - The token signature is valid (signed by the OIDC provider's private key)
 *   - The token has not expired (exp claim)
 *   - The issuer matches our expected OIDC provider (iss claim)
 *   - The audience matches our client ID (aud claim)
 *   - The nonce matches to prevent replay attacks
 */
async function verifyIdToken(idToken, expectedNonce) {
  // First, decode the header (without verification) to get the key ID (kid)
  const decodedHeader = jwt.decode(idToken, { complete: true });
  if (!decodedHeader || !decodedHeader.header) {
    throw new Error('Invalid id_token: unable to decode header');
  }

  // Ensure the algorithm is an asymmetric one (prevent algorithm confusion attacks)
  const allowedAlgorithms = ['RS256', 'RS384', 'RS512', 'ES256', 'ES384', 'ES512', 'PS256', 'PS384', 'PS512'];
  if (!allowedAlgorithms.includes(decodedHeader.header.alg)) {
    throw new Error(`Unsupported or insecure algorithm: ${decodedHeader.header.alg}`);
  }

  // Fetch the signing key from the JWKS endpoint
  const signingKey = await getSigningKey(decodedHeader.header);

  // Verify the token with full cryptographic signature verification
  const verifyOptions = {
    algorithms: allowedAlgorithms,
    issuer: OIDC_CONFIG.issuer,
    audience: OIDC_CONFIG.clientId,
    clockTolerance: 30, // Allow 30 seconds of clock skew
    maxAge: '1h', // Token must not be older than 1 hour
  };

  return new Promise((resolve, reject) => {
    jwt.verify(idToken, signingKey, verifyOptions, (err, decoded) => {
      if (err) {
        return reject(new Error(`id_token verification failed: ${err.message}`));
      }

      // Validate nonce to prevent replay attacks
      if (expectedNonce && decoded.nonce !== expectedNonce) {
        return reject(new Error('id_token nonce mismatch - possible replay attack'));
      }

      // Validate required claims exist
      if (!decoded.sub) {
        return reject(new Error('id_token missing required "sub" claim'));
      }

      // If aud is an array, verify azp (authorized party) matches our client_id
      if (Array.isArray(decoded.aud) && decoded.aud.length > 1) {
        if (decoded.azp !== OIDC_CONFIG.clientId) {
          return reject(new Error('id_token "azp" claim does not match client_id'));
        }
      }

      resolve(decoded);
    });
  });
}

